// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 163577857
#define MAXN 1000005

long long a[MAXN], c[MAXN], p[MAXN];
long long powmod(long long a, long long b, long long mod) {
    long long res = 1;
    while (b) {
        if (b & 1) res = res * a % mod;
        a = a * a % mod;
        b >>= 1;
    }
    return res;
}

long long inv(long long a, long long mod) {
    return powmod(a, mod - 2, mod);
}

int main() {
    int N, h, x, K;
    scanf("%d %d %d %d", &N, &h, &x, &K);
    for (int i = 1; i <= N; i++) scanf("%lld", &p[i]);
    for (int i = 1; i <= K; i++) scanf("%lld", &a[i]);
    for (int i = 1; i <= K; i++) scanf("%lld", &c[i]);
    for (int i = K + 1; i <= h; i++) {
        a[i] = 0;
        for (int j = 1; j <= K; j++) a[i] = (a[i] + c[j] * a[i - j]) % MOD;
    }
    long long sum = 0;
    for (int i = 1; i <= h; i++) sum = (sum + a[i]) % MOD;
    long long ans = 0;
    for (int i = 1; i <= h; i++) {
        long long cnt = 0;
        for (int j = 1; j <= N; j++) {
            if (p[j] >= i && p[j] < i + x) cnt++;
        }
        ans = (ans + cnt * a[i] % MOD * inv(sum, MOD)) % MOD;
    }
    printf("%lld\n", ans);
    return 0;
}

